#include <vector>
#include <algorithm>

using namespace std;

long long solve(std::vector<long long> nums, long long k) {
    sort(nums.begin(), nums.end());
    int n = nums.size();
    int min_removal = n - 1; // Maximum possible removal is n-1 (leaving one element)

    for (int i = 0; i < n; ++i) {
        long long min_val = nums[i];
        // Find the largest element in nums <= min_val * k
        auto it = upper_bound(nums.begin(), nums.end(), min_val * k);
        int j = distance(nums.begin(), it);
        // The window from i to j-1 is valid
        int current_removal = n - (j - i);
        if (current_removal < min_removal) {
            min_removal = current_removal;
        }
    }

    return min_removal;
}
